from dataclasses import dataclass
from typing import Optional


@dataclass
class ChangeWorkflowState:
    request: DesignChangeRequest
    classifier: str            # who classified (Design Lead)
    classified_at: str         # ISO-8601
    approver: Optional[str] = None
    approved_at: Optional[str] = None
    implemented: bool = False
    artifacts_updated: list[str] = field(default_factory=list)   # updated artifact IDs
    refreeze_triggered: bool = False

    def is_complete(self) -> bool:
        if self.request.category == ChangeCategory.COSMETIC:
            return self.implemented
        if self.request.requires_refreeze:
            return self.implemented and self.refreeze_triggered and bool(self.approved_at)
        return self.implemented and bool(self.approved_at)

    def blocking_steps(self) -> list[str]:
        steps = []
        if not self.request.category:
            steps.append("Change not yet classified")
        if self.request.category != ChangeCategory.COSMETIC and not self.approved_at:
            steps.append(f"Awaiting approval from {self.request.approved_by or 'approver'}")
        if not self.implemented:
            steps.append("Not yet implemented")
        if self.request.requires_refreeze and not self.refreeze_triggered:
            steps.append("Handoff package re-freeze not triggered")
        return steps

from dataclasses import dataclass, field


@dataclass
class ChangeLog:
    flow_id: str
    system_prompt_version: str
    entries: list[ChangeWorkflowState] = field(default_factory=list)

    def add(self, state: ChangeWorkflowState) -> None:
        self.entries.append(state)

    def safety_relevant_changes(self) -> list[ChangeWorkflowState]:
        return [
            e for e in self.entries
            if e.request.category in (
                ChangeCategory.SAFETY_LEGAL, ChangeCategory.SCOPE_CHANGE
            )
        ]

    def unapproved_non_cosmetic(self) -> list[ChangeWorkflowState]:
        return [
            e for e in self.entries
            if e.request.category != ChangeCategory.COSMETIC
            and not e.approved_at
        ]

    def to_audit_record(self) -> list[dict]:
        return [
            {
                "change_id": e.request.change_id,
                "category": e.request.category.value if e.request.category else "unclassified",
                "description": e.request.description,
                "approved_by": e.approver,
                "approved_at": e.approved_at,
                "implemented": e.implemented,
                "refreeze_triggered": e.refreeze_triggered,
                "gate_reviews": e.request.gate_reviews_required(),
            }
            for e in self.entries
        ]
